#include <string>

int countWords(std::ifstream &file, std::string word) {
    int wordCount = 0;
    std::string line;
    while (std::getline(file, line)) {
        for (char c : line) {
            if (c == word[0]) {
                if (word[1] == c) {
                    if (word[2] == c) {
                        wordCount++;
                    } else {
                        break;
                    }
                } else {
                    wordCount = 0;
                    break;
                }
            }
        }
    }
    return wordCount;
}

int main() {
    std::string word = "apple";
    std::string file_name = "words.txt";
    std::ifstream file(file_name);
    int count = countWords(file, word);
    std::cout << "Number of occurrences of " << word << ": " << count << std::endl;
    return 0;
}

def longest_common_subsequence(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = 1 + dp[i - 1][j - 1]
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    return dp[m][n]

def fibonacci_dp(n): 
    fibonacci = [0, 1] 
    if n == 0: 
        return fibonacci[0] 
    if n == 1: 
        return fibonacci[1] 
    else: 
        for fibo in range(2, n+1): 
            fibonacci[fibo] = fibonacci[fibo-1] + fibonacci[fibo-2] 
        return fibonacci[n]

def binary_search(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = low + (high - low)//2
        if arr[mid] == target:
            return mid

        if arr[mid] < target:
            low = mid + 1

        else:
            high = mid - 1

    return -1

class Queue:
  def __init__(self):
    self.stack1 = []
    self.stack2 = []

  def enqueue(self, item):
    self.stack1.append(item)

  def dequeue(self):
    if not self.empty():
      item = self.stack2.pop()
      self.stack1.append(item)
      return item

  def peek(self):
    if not self.empty():
      return self.stack2[-1]

  def empty(self):
    return not self.stack1

  def size(self):
    return len(self.stack1)

  def print_all(self):
    print(self.stack1)
    print(self.stack2)
